import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useParams, Navigate } from 'react-router-dom';
import { Home as HomeIcon, Trophy, Search, User, LogOut, Upload, ListMusic, Disc } from 'lucide-react';

// --- ĐỊNH NGHĨA STYLE TRƯỚC KHI DÙNG (Để tránh lỗi ReferenceError) ---
const navBarStyle = { padding: '10px 40px', background: '#1db954', display: 'flex', justifyContent: 'space-between', alignItems: 'center', color: 'white', position: 'sticky', top: 0, zIndex: 1000 };
const logoStyle = { fontWeight: 'bold', textDecoration: 'none', color: 'white', fontSize: '22px', display: 'flex', alignItems: 'center', gap: '10px' };
const navLinkStyle = { textDecoration: 'none', color: 'white', fontWeight: '500', display: 'flex', alignItems: 'center', gap: '5px' };
const uploadBtnStyle = { background: '#000', color: '#fff', padding: '8px 15px', borderRadius: '20px', textDecoration: 'none', fontSize: '13px', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '5px' };
const registerBtnStyle = { textDecoration: 'none', color: 'white', fontWeight: '500', background: 'rgba(255,255,255,0.2)', padding: '5px 15px', borderRadius: '5px' };
const logoutBtnStyle = { padding: '6px 15px', background: '#ff4d4d', color: 'white', border: 'none', borderRadius: '20px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px' };
const profileLinkStyle = { textDecoration: 'none', color: 'white', display: 'flex', alignItems: 'center', gap: '8px' };
const avatarStyle = { width: '30px', height: '30px', background: '#fff', color: '#1db954', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold' };
const footerStyle = { textAlign: 'center', padding: '40px', color: '#888', background: '#f8f9fa', marginTop: 'auto' };

// --- IMPORT CÁC TRANG ---
import Home from './pages/Home/Home';
import SearchPage from './pages/Search/Search';
import Ranking from './pages/Ranking/Ranking';
import Profile from './pages/Profile/Profile';
import Login from './pages/Auth/Login';
import Register from './pages/Auth/Register';
import AdminUpload from './pages/Admin/AdminUpload';

// Các Component tạm thời
const UserPlaylists = () => <div style={{padding: '100px'}}>Danh sách Playlist của bạn</div>;
const PlaylistDetail = () => <div style={{padding: '100px'}}>Chi tiết Playlist</div>;

const ProfileWrapper = () => {
  const { userId } = useParams();
  return <Profile key={userId} />;
};

function App() {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')));

  useEffect(() => {
    const handleStorage = () => setUser(JSON.parse(localStorage.getItem('user')));
    window.addEventListener('storage', handleStorage);
    return () => window.removeEventListener('storage', handleStorage);
  }, []);

  const handleLogout = () => {
    localStorage.clear();
    setUser(null);
    window.location.href = '/login';
  };

  return (
    <Router>
      <div style={{ display: 'flex', flexDirection: 'column', minHeight: '100vh' }}>
        <nav style={navBarStyle}>
          <div style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
            <Link to="/" style={logoStyle}><Disc size={28} /> P2TUNES</Link>
            <Link to="/" style={navLinkStyle}><HomeIcon size={18} /> Trang chủ</Link>
            <Link to="/ranking" style={navLinkStyle}><Trophy size={18} /> BXH</Link>
            <Link to="/search" style={navLinkStyle}><Search size={18} /> Tìm kiếm</Link>
            
            {user && (
              <>
                <Link to="/upload" style={uploadBtnStyle}><Upload size={16} /> Đăng nhạc</Link>
                <Link to={`/playlists/user/${user._id || user.id}`} style={navLinkStyle}><ListMusic size={18} /> Thư viện</Link>
              </>
            )}
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
            {user ? (
              <>
                <Link to={`/profile/${user._id || user.id}`} style={profileLinkStyle}>
                  <div style={avatarStyle}>{user.username?.charAt(0).toUpperCase()}</div>
                  <span>{user.username} {user.role === 'admin' && '⭐'}</span>
                </Link>
                <button onClick={handleLogout} style={logoutBtnStyle}><LogOut size={16} /> Thoát</button>
              </>
            ) : (
              <div style={{ display: 'flex', gap: '15px' }}>
                <Link to="/login" style={navLinkStyle}>Đăng nhập</Link>
                <Link to="/register" style={registerBtnStyle}>Đăng ký</Link>
              </div>
            )}
          </div>
        </nav>

        <main style={{ flex: 1 }}>
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/search" element={<SearchPage />} />
            <Route path="/ranking" element={<Ranking />} />
            <Route path="/login" element={<Login />} />
            <Route path="/register" element={<Register />} />
            <Route path="/profile/:userId" element={<ProfileWrapper />} />
            <Route path="/upload" element={user ? <AdminUpload /> : <Navigate to="/login" />} />
            <Route path="/playlists/user/:userId" element={user ? <UserPlaylists /> : <Navigate to="/login" />} />
            <Route path="/playlist/:playlistId" element={<PlaylistDetail />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>

        <footer style={footerStyle}>© 2025 P2TUNES - SoundCloud Style Music Platform</footer>
      </div>
    </Router>
  );
}

export default App;
